/**
 * Custom error class for OAuth-related errors
 */
class OAuthError extends Error {
  constructor(message, code, statusCode = null) {
    super(message);
    this.name = 'OAuthError';
    this.code = code;
    this.statusCode = statusCode;
  }
}

// ============================================================
// Usage Example / Demo
// ============================================================

// Initialize the OAuth client
const oauthClient = new OAuthImplicitClient({
  clientId: 'your-client-id',
  authorizationEndpoint: 'https://auth.example.com/oauth/authorize',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write profile',
  apiBaseUrl: 'https://api.example.com/v1',
});

// Listen for OAuth events
oauthClient.on('oauth_success', (data) => {
  console.log('Successfully authenticated!', data.tokenData);
  initializeApp();
});

oauthClient.on('oauth_error', (data) => {
  console.error('Authentication error:', data.error, data.errorDescription);
  showLoginScreen();
});

oauthClient.on('oauth_token_expired', () => {
  console.warn('Token expired. Redirecting to login...');
  showLoginScreen();
});

oauthClient.on('oauth_token_refreshed', (data) => {
  console.log('Token refreshed successfully.', data.tokenData);
});

oauthClient.on('oauth_logout', () => {
  console.log('User logged out.');
  showLoginScreen();
});

oauthClient.on('oauth_auto_refresh_failed', (data) => {
  console.warn('Auto-refresh failed. User may need to re-authenticate.', data.error);
});

// Main application logic
function showLoginScreen() {
  const appContainer = document.getElementById('app');
  if (appContainer) {
    appContainer.innerHTML = `
      <div style="text-align: center; margin-top: 100px; font-family: Arial, sans-serif;">
        <h1>Legacy SPA - OAuth 2.0 Demo</h1>
        <p>Please log in to continue.</p>
        <button id="login-btn" style="padding: 12px 24px; font-size: 16px; cursor: pointer;
          background: #4285f4; color: white; border: none; border-radius: 4px;">
          Login with OAuth
        </button>
      </div>
    `;
    document.getElementById('login-btn').addEventListener('click', () => {
      oauthClient.authorize();
    });
  }
}

async function initializeApp() {
  const appContainer = document.getElementById('app');
  const tokenData = oauthClient.getTokenData();
  const timeRemaining = oauthClient.getTokenTimeRemaining();

  if (appContainer) {
    appContainer.innerHTML = `
      <div style="font-family: Arial, sans-serif; max-width: 800px; margin: 20px auto; padding: 20px;">
        <h1>Legacy SPA - Authenticated</h1>
        <div style="background: #e8f5e9; padding: 16px; border-radius: 4px; margin-bottom: 20px;">
          <strong>Access Token:</strong> ${tokenData.accessToken.substring(0, 20)}...
          <br>
          <strong>Token Type:</strong> ${tokenData.tokenType}
          <br>
          <strong>Scope:</strong> ${tokenData.scope}
          <br>
          <strong>Expires In:</strong> <span id="time-remaining">${timeRemaining || 'N/A'}</span> seconds
        </div>
        
        <div style="margin-bottom: 20px;">
          <button id="api-call-btn" style="padding: 8px 16px; margin-right: 8px; cursor: pointer;
            background: #4285f4; color: white; border: none; border-radius: 4px;">
            Make API Call
          </button>
          <button id="refresh-btn" style="padding: 8px 16px; margin-right: 8px; cursor: pointer;
            background: #34a853; color: white; border: none; border-radius: 4px;">
            Silent Refresh
          </button>
          <button id="logout-btn" style="padding: 8px 16px; cursor: pointer;
            background: #ea4335; color: white; border: none; border-radius: 4px;">
            Logout
          </button>
        </div>
        
        <div id="api-response" style="background: #f5f5f5; padding: 16px; border-radius: 4px;
          min-height: 100px; white-space: pre-wrap; font-family: monospace;">
          Click "Make API Call" to test the authenticated request.
        </div>
      </div>
    `;

    // Update time remaining display
    const updateTimer = setInterval(() => {
      const remaining = oauthClient.getTokenTimeRemaining();
      const el = document.getElementById('time-remaining');
      if (el) {
        el.textContent = remaining !== null ? remaining : 'N/A';
      }
      if (!oauthClient.isAuthenticated()) {
        clearInterval(updateTimer);
      }
    }, 1000);

    // API call button
    document.getElementById('api-call-btn').addEventListener('click', async () => {
      const responseEl = document.getElementById('api-response');
      responseEl.textContent = 'Loading...';
      try {
        const data = await oauthClient.get('/user/profile');
        responseEl.textContent = JSON.stringify(data, null, 2);
      } catch (error) {
        responseEl.textContent = `Error: ${error.message}\nCode: ${error.code}`;
      }
    });

    // Silent refresh button
    document.getElementById('refresh-btn').addEventListener('click', async () => {
      const responseEl = document.getElementById('api-response');
      responseEl.textContent = 'Attempting silent refresh...';
      try {
        const newToken = await oauthClient.silentRefresh();
        responseEl.textContent = `Token refreshed!\n${JSON.stringify(newToken, null, 2)}`;
      } catch (error) {
        responseEl.textContent = `Refresh failed: ${error.message}`;
      }
    });

    // Logout button
    document.getElementById('logout-btn').addEventListener('click', () => {
      clearInterval(updateTimer);
      oauthClient.logout();
    });

    // Enable auto-refresh (refresh 60 seconds before expiry)
    oauthClient.enableAutoRefresh(60);
  }
}

// Bootstrap the application
if (oauthClient.isAuthenticated()) {
  initializeApp();
} else {
  showLoginScreen();
}

